我有一个Python脚本用来批量重命名文件，现在功能是OK的但代码很乱，有很多重复逻辑和硬编码的路径。帮我重构一下，让它更清晰、更好维护。脚本内容如下：

import os
import re
import shutil

def process():
    files = os.listdir('/Users/test/downloads')
    for f in files:
        if f.endswith('.jpg') or f.endswith('.jpeg') or f.endswith('.png'):
            match = re.match(r'IMG_(\d{8})_(\d{6})', f)
            if match:
                date = match.group(1)
                folder = '/Users/test/photos/' + date[:4] + '/' + date[4:6]
                if not os.path.exists(folder):
                    os.makedirs(folder)
                shutil.move('/Users/test/downloads/' + f, folder + '/' + f)
        if f.endswith('.mp4') or f.endswith('.mov'):
            match = re.match(r'IMG_(\d{8})_(\d{6})', f)
            if match:
                date = match.group(1)
                folder = '/Users/test/videos/' + date[:4] + '/' + date[4:6]
                if not os.path.exists(folder):
                    os.makedirs(folder)
                shutil.move('/Users/test/downloads/' + f, folder + '/' + f)

process()
